import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode;

public class SecureXSSExample {
    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input by sanitizing and escaping it
        String sanitizedInput = Encode.forHtml(userInput);

        PrintWriter out = new PrintWriter(System.out);
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>Welcome, " + sanitizedInput + "</h1>");
        out.println("</body>");
        out.println("</html>");

        // The sanitized input will be displayed as plain text on the page, preventing XSS attacks
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
